# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import json
import pymysql
import os
from typing import Dict, Any, List

def lambda_handler(event, context):
    # Database connection parameters
    db_config = {
        'host': os.environ['DB_HOST'],
        'user': os.environ['DB_USER'],
        'password': os.environ['DB_PASSWORD'],
        'database': os.environ['DB_NAME'],
        'port': int(os.environ.get('DB_PORT', 3306)),
        'charset': 'utf8mb4'
    }
    
    # Parse query parameters
    query_params = event.get('queryStringParameters', {})
    if not query_params:
        query_params = {}
    
    # Build dynamic SQL query
    sql_conditions = []
    params = []
    
    # Handle search term
    search_term = query_params.get('search')
    if search_term:
        sql_conditions.append("(name LIKE %s OR description LIKE %s)")
        params.extend([f"%{search_term}%", f"%{search_term}%"])
    
    # Handle category filter
    category = query_params.get('category')
    if category:
        sql_conditions.append("category = %s")
        params.append(category)
    
    # Handle price range
    min_price = query_params.get('min_price')
    max_price = query_params.get('max_price')
    if min_price:
        sql_conditions.append("price >= %s")
        params.append(float(min_price))
    if max_price:
        sql_conditions.append("price <= %s")
        params.append(float(max_price))
    
    # Handle stock status
    in_stock = query_params.get('in_stock')
    if in_stock is not None:
        sql_conditions.append("stock_quantity > 0" if in_stock.lower() == 'true' else "stock_quantity = 0")
    
    # Build final query
    base_query = "SELECT * FROM products WHERE 1=1"
    if sql_conditions:
        base_query += " AND " + " AND ".join(sql_conditions)
    
    # Add sorting and pagination
    sort_by = query_params.get('sort_by', 'name')
    sort_order = query_params.get('sort_order', 'ASC')
    if sort_by in ['name', 'price', 'category', 'created_at']:
        base_query += f" ORDER BY {sort_by} {sort_order}"
    
    # Pagination
    page = int(query_params.get('page', 1))
    page_size = int(query_params.get('page_size', 10))
    offset = (page - 1) * page_size
    base_query += f" LIMIT {page_size} OFFSET {offset}"
    
    try:
        # Connect to database
        connection = pymysql.connect(**db_config)
        
        with connection.cursor(pymysql.cursors.DictCursor) as cursor:
            cursor.execute(base_query, params)
            results = cursor.fetchall()
            
            # Get total count for pagination info
            count_query = "SELECT COUNT(*) as total FROM products WHERE 1=1"
            if sql_conditions:
                count_query += " AND " + " AND ".join(sql_conditions)
            
            cursor.execute(count_query, params)
            total_count = cursor.fetchone()['total']
            
        response = {
            'statusCode': 200,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({
                'products': results,
                'pagination': {
                    'page': page,
                    'page_size': page_size,
                    'total': total_count,
                    'pages': (total_count + page_size - 1) // page_size
                }
            })
        }
        
    except Exception as e:
        response = {
            'statusCode': 500,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({
                'error': str(e)
            })
        }
    finally:
        if 'connection' in locals():
            connection.close()
    
    return response